package com.seaquake6324.civitas.domain.territory;
import static org.junit.jupiter.api.Assertions.*;import com.seaquake6324.civitas.domain.*;import java.util.*;import org.junit.jupiter.api.Test;
class ExpansionEligibilityTest{
 @Test void founderHasDefaultMilitaryAuthorityButOtherMembersDoNot(){UUID founder=UUID.randomUUID(),member=UUID.randomUUID();long core=ChunkCoordinate.pack(0,0);City city=new City(UUID.randomUUID(),"A",0,"minecraft:overworld",0,core,0,founder,founder,Set.of(founder,member),Set.of(core));assertTrue(city.mayCommandMilitary(founder));assertFalse(city.mayCommandMilitary(member));}
 @Test void requiresCardinalSourceCoverageAndCooldown(){UUID leader=UUID.randomUUID();long core=ChunkCoordinate.pack(0,0),target=ChunkCoordinate.pack(1,0);City city=new City(UUID.randomUUID(),"A",0,"minecraft:overworld",0,core,0,leader,leader,Set.of(leader),Set.of(core));Map<Long,ExpansionEligibility.ChunkHealth> health=Map.of(core,new ExpansionEligibility.ChunkHealth(40,20,0,0));var rules=new ExpansionEligibility.Rules(40,20,.5,1.0/3,12000);var valid=ExpansionEligibility.evaluate(city,new ExpansionEligibility.Context(true,true,true,false,false,12000,target,core,health),rules);assertTrue(valid.eligible(),valid.failures().toString());var diagonal=ExpansionEligibility.evaluate(city,new ExpansionEligibility.Context(true,true,true,false,false,12000,ChunkCoordinate.pack(1,1),core,health),rules);assertTrue(diagonal.failures().contains(ExpansionEligibility.Failure.NOT_ADJACENT));var cooling=ExpansionEligibility.evaluate(city.claim(target,core,12000),new ExpansionEligibility.Context(true,true,true,false,false,12001,ChunkCoordinate.pack(2,0),target,Map.of(core,health.get(core),target,health.get(core))),rules);assertTrue(cooling.failures().contains(ExpansionEligibility.Failure.COOLDOWN));}
 @Test void developmentRequiresCivilityAndActivityOnTheSameLayer(){var split=new ExpansionEligibility.ChunkHealth(40,0,0,20);assertFalse(split.developed(40,20));assertTrue(new ExpansionEligibility.ChunkHealth(40,20,0,0).developed(40,20));}
 @Test void rejectsExpansionFromAnAlreadyBrokenTerritory(){UUID leader=UUID.randomUUID();long core=ChunkCoordinate.pack(0,0),island=ChunkCoordinate.pack(3,0),target=ChunkCoordinate.pack(1,0);City city=new City(UUID.randomUUID(),"Broken",0,"minecraft:overworld",0,core,0,leader,leader,Set.of(leader),Set.of(core,island));var healthy=new ExpansionEligibility.ChunkHealth(40,20,0,0);var result=ExpansionEligibility.evaluate(city,new ExpansionEligibility.Context(true,true,true,false,false,12000,target,core,Map.of(core,healthy,island,healthy)),new ExpansionEligibility.Rules(40,20,.5,1.0/3,12000));assertTrue(result.failures().contains(ExpansionEligibility.Failure.CURRENT_TERRITORY_DISCONNECTED));}
}
